const CSS = `
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&display=swap');
.smoo *{box-sizing:border-box;}
.smoo{
  --bg:#EDF1E6; --surface:#FBFDF7; --ink:#17301F; --ink-soft:#506452;
  --line:#D8DFCC; --leaf:#2F7D4F; --leaf-deep:#235E3B; --sage:#A9BBA0; --tint:#E7F0E7;
  --warn:#B5543C; --warn-tint:#F4E4DE;
  font-family:'JetBrains Mono', ui-monospace, monospace;
  background:var(--bg); color:var(--ink); box-sizing:border-box; min-height:100vh; min-height:100dvh;
  padding:0 16px 60px; -webkit-font-smoothing:antialiased; text-rendering:optimizeLegibility;
}
.smoo .wrap{max-width:620px; margin:0 auto;}
.smoo .head{padding-top:16px;}
.smoo .brand{display:flex; align-items:center; gap:9px;}
.smoo .brand .word{display:flex; align-items:baseline; gap:2px;}
.smoo .glass{width:30px; height:37px; flex:none; transform:rotate(-9deg); transform-origin:55% 92%;}
.smoo .glass .g-body{fill:var(--surface);}
.smoo .glass .g-fill{fill:var(--leaf);}
.smoo .glass .g-top{fill:#5AA876;}
.smoo .glass .g-bub{fill:#ffffff; opacity:.34;}
.smoo .glass .g-outline{fill:none; stroke:var(--leaf-deep); stroke-width:1.6; stroke-linejoin:round;}
.smoo .glass .g-straw{fill:none; stroke:var(--warn); stroke-width:2.4; stroke-linecap:round;}
.smoo .glass .g-leaf{fill:var(--leaf-deep);}
.smoo .brand b{font-weight:700; font-size:23px; letter-spacing:-1px; color:var(--ink);}
.smoo .brand small{font-weight:500; font-size:12px; color:var(--sage);}

.smoo .control{z-index:20; background:var(--bg); padding:11px 0 10px; border-bottom:1px solid var(--line);}
.smoo .control.flow{position:static;}
.smoo .selbar{display:flex; align-items:center; gap:9px; justify-content:space-between; cursor:pointer; user-select:none; min-height:34px;}
.smoo .selbar:hover .chev{color:var(--leaf-deep);}
.smoo .selbar:focus-visible{outline:2px solid var(--leaf-deep); outline-offset:3px; border-radius:9px;}
.smoo .selchips{display:flex; flex-wrap:wrap; gap:6px; align-items:center; flex:1; min-width:0;}
.smoo .prompt{font-size:13.5px; color:var(--ink-soft);}
.smoo .selchip{font-weight:500; font-size:11.5px; color:#fff; background:var(--leaf); border-radius:999px; padding:4px 10px 4px 5px; display:inline-flex; align-items:center; gap:6px;}
.smoo .selchip .o{background:rgba(255,255,255,.24); width:14px; height:14px; border-radius:50%; display:grid; place-items:center; font-size:8.5px; font-weight:700;}
.smoo .chev{flex:none; font-size:12px; color:var(--sage); width:30px; text-align:center; line-height:1; transition:color .15s; pointer-events:none;}
.smoo .chev.live{color:var(--leaf-deep);}
.smoo .achip{font-family:inherit; font-weight:500; font-size:11.5px; padding:5px 11px 5px 8px; border-radius:999px; border:1px solid var(--sage); background:transparent; color:var(--ink-soft); cursor:pointer; display:inline-flex; align-items:center; gap:5px; transition:background .15s, border-color .15s, color .15s;}
.smoo .achip .ae{font-size:13px; line-height:1;}
.smoo .achip:hover{border-color:var(--warn);}
.smoo .achip.on{background:var(--warn-tint); border-color:var(--warn); color:var(--warn);}
.smoo .achip.on .al{text-decoration:line-through;}
.smoo .achip:focus-visible{outline:2px solid var(--warn); outline-offset:2px;}
.smoo .panel{overflow:hidden; transform-origin:top center; will-change:max-height, transform;}
.smoo .tags{display:flex; flex-wrap:wrap; justify-content:center; gap:8px; padding:13px 2px 2px;}
.smoo .tag{
  position:relative; font-family:inherit; font-weight:500; font-size:12.5px; line-height:1;
  padding:8px 12px; border-radius:999px; border:1.5px solid var(--sage);
  background:var(--surface); color:var(--ink); cursor:pointer;
  transform:translateX(var(--dx,0)) rotate(var(--tilt,0deg));
  transition:transform .22s cubic-bezier(.34,1.56,.64,1), background .15s, border-color .15s, color .15s, opacity .15s;
}
.smoo .tag:hover:not(.off):not(.on){border-color:var(--leaf); transform:translateX(0) rotate(0deg) scale(1.04);}
.smoo .tag.on{background:var(--leaf); border-color:var(--leaf); color:#fff; transform:translateX(0) rotate(0deg) scale(1.12);}
.smoo .tag.off{opacity:.3; cursor:not-allowed;}
.smoo .tag:focus-visible{outline:2px solid var(--leaf-deep); outline-offset:2px;}
.smoo .num{position:absolute; top:-6px; right:-5px; width:16px; height:16px; border-radius:50%; background:#fff; color:var(--leaf-deep); border:1.5px solid var(--leaf); font-size:9.5px; font-weight:700; display:grid; place-items:center; box-shadow:0 1px 3px rgba(23,48,31,.22);}
.smoo .bar{display:flex; justify-content:space-between; align-items:center; margin-top:14px; font-size:12px;}
.smoo .toggle{font-family:inherit; background:none; border:none; color:var(--ink-soft); font-size:12px; cursor:pointer; padding:4px 0; display:flex; gap:5px; align-items:center;}
.smoo .toggle b{color:var(--leaf-deep); font-weight:500;}
.smoo .link{font-family:inherit; background:none; border:none; color:var(--leaf-deep); font-size:12px; cursor:pointer; text-decoration:underline; padding:4px 0;}
.smoo .refine{margin-top:11px; padding:13px 13px 3px; border:1px solid var(--line); border-radius:12px; background:var(--surface);}
.smoo .frow{margin-bottom:11px;}
.smoo .flabel{font-size:10.5px; color:var(--sage); font-weight:500; margin-bottom:7px; letter-spacing:.3px;}
.smoo .fchips{display:flex; flex-wrap:wrap; gap:6px;}
.smoo .fchip{font-family:inherit; font-weight:500; font-size:11.5px; padding:5px 10px; border-radius:999px; border:1px solid var(--sage); background:transparent; color:var(--ink-soft); cursor:pointer; transition:background .15s, border-color .15s, color .15s;}
.smoo .fchip:hover{border-color:var(--leaf);}
.smoo .fchip.on{background:var(--tint); border-color:var(--leaf); color:var(--leaf-deep);}
.smoo .fchip:focus-visible{outline:2px solid var(--leaf-deep); outline-offset:2px;}

.smoo .results{margin-top:20px;}
.smoo .rhead{font-weight:600; font-size:14px; margin-bottom:14px; color:var(--ink);}
.smoo .rhead span{font-weight:400; color:var(--ink-soft); font-size:12px;}
.smoo .divider{font-size:11px; color:var(--sage); letter-spacing:.4px; margin:16px 2px 13px; display:flex; align-items:center; gap:10px;}
.smoo .divider:before,.smoo .divider:after{content:''; height:1px; background:var(--line); flex:1;}
.smoo .card{background:var(--surface); border:1px solid var(--line); border-radius:13px; padding:14px 15px; margin-bottom:11px;}
.smoo .ctop{display:flex; justify-content:space-between; align-items:flex-start; gap:12px;}
.smoo .card h3{margin:0; font-weight:600; font-size:15.5px; color:var(--ink); letter-spacing:-.2px;}
.smoo .dots{display:flex; gap:4px; padding-top:6px; flex:none;}
.smoo .dot{width:7px; height:7px; border-radius:50%; background:var(--sage); opacity:.38;}
.smoo .dot.f{background:var(--leaf); opacity:1;}
.smoo .meta{display:flex; gap:6px; flex-wrap:wrap; margin-top:8px;}
.smoo .badge{font-size:10.5px; color:var(--leaf-deep); border:1px solid var(--line); border-radius:5px; padding:2px 7px; font-weight:500;}
.smoo .emoji{display:flex; flex-wrap:wrap; gap:6px; margin-top:11px; font-size:17px; line-height:1;}
.smoo .ing{list-style:none; margin:12px 0 0; padding:12px 0 2px; border-top:1px solid var(--line);}
.smoo .ing li{display:flex; gap:9px; padding:2.5px 0; align-items:flex-start;}
.smoo .ing .mk{flex:none; width:4px; height:4px; border-radius:50%; background:var(--sage); margin-top:7px;}
.smoo .ing .tx{flex:1; min-width:0; font-size:13px; color:var(--ink-soft); line-height:1.5;}
.smoo .ing .amt{color:var(--ink); font-weight:600;}
.smoo .cfoot{margin-top:12px; text-align:right;}
.smoo .copy{font-family:inherit; font-weight:500; font-size:11.5px; color:var(--ink-soft); background:transparent; border:1px solid var(--sage); border-radius:7px; padding:5px 11px; cursor:pointer; transition:border-color .15s, color .15s;}
.smoo .copy:hover{border-color:var(--leaf); color:var(--leaf-deep);}
.smoo .copy.done{border-color:var(--leaf); color:var(--leaf);}
.smoo .copy:focus-visible{outline:2px solid var(--leaf-deep); outline-offset:2px;}
.smoo .more{display:block; width:100%; margin-top:5px; font-family:inherit; font-weight:500; font-size:12.5px; color:var(--leaf-deep); background:transparent; border:1px dashed var(--sage); border-radius:10px; padding:11px; cursor:pointer; transition:border-color .15s;}
.smoo .more:hover{border-color:var(--leaf);}
.smoo .none{margin-top:22px; padding:22px; border:1px dashed var(--sage); border-radius:12px; color:var(--ink-soft); font-size:13px; text-align:center; background:var(--surface); line-height:1.6;}
@media (prefers-reduced-motion: reduce){ .smoo *{transition:none !important;} .smoo .tag{transform:none !important;} .smoo .tag.on{transform:scale(1.1) !important;} .smoo .panel{transition:none !important;} }
`;

async function copyText(text) {
  try { if (navigator.clipboard && window.isSecureContext) { await navigator.clipboard.writeText(text); return true; } } catch (e) { }
  try {
    const ta = document.createElement('textarea'); ta.value = text; ta.style.position = 'fixed'; ta.style.opacity = '0';
    document.body.appendChild(ta); ta.focus(); ta.select();
    const ok = document.execCommand('copy'); document.body.removeChild(ta); return ok;
  } catch (e) { return false; }
}
function tierLabel(score, n) { if (score === n) return null; if (score === n - 1) return 'close matches'; return 'loosely related'; }
function scrollY() { return window.pageYOffset || document.documentElement.scrollTop || document.body.scrollTop || 0; }
function splitAmt(s) { const m = s.match(AMT); if (m && /\d/.test(m[0])) { const a = m[0].trim(); return [a, s.slice(m[0].length).trim()]; } return [null, s]; }

export default function App() {
  const [sel, setSel] = useState([]);
  const [dietSel, setDietSel] = useState([]);
  const [seasonSel, setSeasonSel] = useState([]);
  const [avoidSel, setAvoidSel] = useState([]);
  const [condensed, setCondensed] = useState(false);
  const [refineOpen, setRefineOpen] = useState(false);
  const [expanded, setExpanded] = useState(false);
  const [copiedId, setCopiedId] = useState(null);

  const panelRef = useRef(null);
  const condRef = useRef(false);
  const lastY = useRef(0);
  const mounted = useRef(false);
  const lockUntil = useRef(0);
  const refineOpenRef = useRef(false);
  const instant = useRef(false);


  const setCond = (v) => { lockUntil.current = Date.now() + 450; condRef.current = v; setCondensed(v); };

  useEffect(() => {
    const el = panelRef.current; if (!el) return;
    if (!mounted.current) {
      mounted.current = true;
      if (condensed) { el.style.maxHeight = '0px'; el.style.transform = COLLAPSED_T; el.style.overflow = 'hidden'; }
      else { el.style.maxHeight = 'none'; el.style.transform = 'none'; el.style.overflow = 'visible'; }
      return;
    }
    if (instant.current) {
      instant.current = false;
      el.style.transition = 'none'; el.style.overflow = 'hidden';
      el.style.maxHeight = '0px'; el.style.transform = COLLAPSED_T;
      return;
    }
    el.style.overflow = 'hidden';
    if (condensed) {
      el.style.transition = 'none';
      el.style.maxHeight = el.scrollHeight + 'px'; el.style.transform = 'translateY(0)';
      void el.offsetHeight;
      el.style.transition = 'max-height .30s ' + EASE_IN + ', transform .30s ' + EASE_IN;
      el.style.maxHeight = '0px'; el.style.transform = COLLAPSED_T;
    } else {
      el.style.transition = 'none';
      el.style.maxHeight = '0px'; el.style.transform = COLLAPSED_T;
      void el.offsetHeight;
      el.style.transition = 'max-height .44s ' + EASE_OUT + ', transform .44s ' + EASE_OUT;
      el.style.maxHeight = el.scrollHeight + 'px'; el.style.transform = 'translateY(0)';
    }
  }, [condensed]);

  useEffect(() => {
    const el = panelRef.current; if (!el || condensed || !mounted.current) return;
    el.style.maxHeight = 'none';
  }, [refineOpen, sel, dietSel, seasonSel, avoidSel]);

  useEffect(() => { refineOpenRef.current = refineOpen; }, [refineOpen]);

  const onPanelEnd = (e) => {
    if (e.propertyName !== 'max-height') return;
    const el = panelRef.current; if (!el) return;
    if (!condRef.current) { el.style.maxHeight = 'none'; el.style.transform = 'none'; el.style.overflow = 'visible'; }
  };

  const n = sel.length;
  const toggle = (k) => { setExpanded(false); setSel(s => s.includes(k) ? s.filter(x => x !== k) : (s.length >= MAX ? s : [...s, k])); };
  const toggleDiet = (k) => { setExpanded(false); setDietSel(s => s.includes(k) ? s.filter(x => x !== k) : [...s, k]); };
  const toggleSeason = (k) => { setExpanded(false); setSeasonSel(s => s.includes(k) ? s.filter(x => x !== k) : [...s, k]); };
  const toggleAvoid = (e) => { setExpanded(false); setAvoidSel(s => s.includes(e) ? s.filter(x => x !== e) : [...s, e]); };
  const clearAll = () => { setSel([]); setDietSel([]); setSeasonSel([]); setAvoidSel([]); setExpanded(false); };
  const clearFilters = () => { setDietSel([]); setSeasonSel([]); setAvoidSel([]); setExpanded(false); };
  const togglePanel = () => setCond(!condRef.current);
  const toggleRefine = () => {
    const nv = !refineOpenRef.current; refineOpenRef.current = nv;
    setRefineOpen(nv); setExpanded(false);
    requestAnimationFrame(() => requestAnimationFrame(() => {
      window.scrollTo({ top: nv ? document.documentElement.scrollHeight : 0, behavior: 'smooth' });
    }));
  };
  const filtersActive = dietSel.length > 0 || seasonSel.length > 0 || avoidSel.length > 0;
  const avoidKw = useMemo(() => { const out = []; AVOID.forEach(a => { if (avoidSel.includes(a.e)) a.kw.forEach(k => out.push(k)); }); return out; }, [avoidSel]);

  const scored = useMemo(() => {
    if (n === 0) return [];
    return RECIPES.map(r => {
      const matched = r.feeling_tags.filter(t => sel.includes(t));
      return { ...r, score: matched.length, matched };
    }).filter(r => r.score > 0)
      .sort((a, b) => b.score - a.score || a.ingredients.length - b.ingredients.length || a.name.localeCompare(b.name));
  }, [sel, n]);

  const filtered = useMemo(() => scored.filter(r => {
    for (const df of dietSel) { if (!(r.diet_flags || []).includes(df)) return false; }
    if (seasonSel.length > 0) { if (!r.season || !seasonSel.includes(r.season)) return false; }
    if (avoidKw.length > 0) {
      const t = r.ingredients.join(' || ').toLowerCase().replace(/cherry tomato(es)?/g, 'tomato');
      for (const k of avoidKw) { if (t.includes(k)) return false; }
    }
    return true;
  }), [scored, dietSel, seasonSel, avoidKw]);

  const strong = (n >= 2) ? filtered.filter(r => r.score >= 2) : [];
  const hasStrong = strong.length > 0;
  const pool = (n >= 2 && hasStrong) ? strong : filtered;
  const collapsedShown = Math.min(pool.length, CAP);
  const visible = expanded ? filtered : pool.slice(0, CAP);
  const moreCount = filtered.length - collapsedShown;
  const usingStrong = (n >= 2 && hasStrong && !expanded);
  const headCount = expanded ? filtered.length : pool.length;
  const headWord = usingStrong ? (headCount === 1 ? 'strong match' : 'strong matches') : (headCount === 1 ? 'blend' : 'blends');

  const onCopy = async (r) => {
    const text = r.name + "\n\n" + r.ingredients.join("\n");
    const ok = await copyText(text);
    if (ok) { setCopiedId(r.id); setTimeout(() => setCopiedId(c => c === r.id ? null : c), 1600); }
  };

  return (
    <div className="smoo">
      <style>{CSS}</style>
      <div className="wrap">
        <div className="head">
          <div className="brand">
            <svg className="glass" viewBox="0 0 28 34" aria-hidden="true">
              <path className="g-body" d="M5.5 7 L22.5 7 L20.3 29 Q19.9 31.4 17.6 31.4 L10.4 31.4 Q8.1 31.4 7.7 29 Z" />
              <path className="g-fill" d="M6.1 12 L21.9 12 L20.3 29 Q19.9 31.4 17.6 31.4 L10.4 31.4 Q8.1 31.4 7.7 29 Z" />
              <ellipse className="g-top" cx="14" cy="12" rx="7.6" ry="1.3" />
              <circle className="g-bub" cx="11" cy="18.5" r="1.1" />
              <circle className="g-bub" cx="13.6" cy="23" r="0.8" />
              <path className="g-outline" d="M5.5 7 L22.5 7 L20.3 29 Q19.9 31.4 17.6 31.4 L10.4 31.4 Q8.1 31.4 7.7 29 Z" />
              <path className="g-straw" d="M14.8 16 L19.8 2.6" />
              <path className="g-leaf" d="M8.7 6.5 Q4.8 5.0 5.7 1.3 Q9.6 2.8 8.7 6.5 Z" />
            </svg>
            <span className="word"><b>smoo</b><small>.casa</small></span>
          </div>
        </div>

        <div className={"control" + (refineOpen ? " flow" : "")}>
          <div className="selbar" role="button" tabIndex={0}
            aria-expanded={!condensed} aria-label={condensed ? 'expand feelings' : 'collapse feelings'}
            onClick={togglePanel}
            onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); togglePanel(); } }}>
            <div className="selchips">
              {n === 0
                ? <span className="prompt">how've you been feeling lately?</span>
                : sel.map((k, i) => (
                  <span key={k} className="selchip"><span className="o">{i + 1}</span>{LABEL[k]}</span>
                ))}
            </div>
            <span className={"chev" + (!condensed ? " live" : "")} aria-hidden="true">{condensed ? '▾' : '▴'}</span>
          </div>

          <div ref={panelRef} className="panel" aria-hidden={condensed} onTransitionEnd={onPanelEnd}>
            <div className="tags">
              {FEELINGS.map(([k, label], idx) => {
                const on = sel.includes(k);
                const off = !on && sel.length >= MAX;
                const order = sel.indexOf(k) + 1;
                return (
                  <button key={k} className={"tag" + (on ? " on" : "") + (off ? " off" : "")}
                    style={{ '--tilt': TILT[idx] + 'deg', '--dx': DX[idx] + 'px', zIndex: on ? 40 - idx : undefined }}
                    aria-pressed={on} disabled={off} onClick={() => toggle(k)}>
                    {label}{on && <span className="num">{order}</span>}
                  </button>
                );
              })}
            </div>
            <div className="bar">
              <button className="toggle" onClick={toggleRefine}>
                refine {filtersActive && <b>· {dietSel.length + seasonSel.length + avoidSel.length}</b>} {refineOpen ? '▴' : '▾'}
              </button>
              {(sel.length > 0 || filtersActive) && <button className="link" onClick={clearAll}>clear all</button>}
            </div>
            {refineOpen && (
              <div className="refine">
                <div className="frow">
                  <div className="flabel">diet</div>
                  <div className="fchips">
                    {DIET.map(([k, label]) => (
                      <button key={k} className={"fchip" + (dietSel.includes(k) ? " on" : "")} onClick={() => toggleDiet(k)}>{label}</button>
                    ))}
                  </div>
                </div>
                <div className="frow">
                  <div className="flabel">season</div>
                  <div className="fchips">
                    {SEASONS.map(([k, label]) => (
                      <button key={k} className={"fchip" + (seasonSel.includes(k) ? " on" : "")} onClick={() => toggleSeason(k)}>{label}</button>
                    ))}
                  </div>
                </div>
                <div className="frow">
                  <div className="flabel">avoid · tap to hide</div>
                  <div className="fchips">
                    {AVOID.map(a => (
                      <button key={a.e} className={"achip" + (avoidSel.includes(a.e) ? " on" : "")} onClick={() => toggleAvoid(a.e)} aria-pressed={avoidSel.includes(a.e)}>
                        <span className="ae" aria-hidden="true">{a.e}</span><span className="al">{a.label}</span>
                      </button>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>

        {n > 0 && (
          filtered.length === 0 ? (
            <div className="none">nothing matches those filters. {filtersActive && <button className="link" onClick={clearFilters}>clear filters</button>}</div>
          ) : (
            <div className="results">
              <div className="rhead">{headCount} {headWord} <span>· best first</span></div>
              {visible.map((r, i) => {
                const prev = i > 0 ? visible[i - 1].score : null;
                const divider = (prev !== null && r.score < prev) ? tierLabel(r.score, n) : null;
                const metaTags = [...(r.diet_flags || []).filter(f => DIET_LABEL[f]).map(f => DIET_LABEL[f]), ...(r.season ? [r.season.toLowerCase()] : [])];
                return (
                  <React.Fragment key={r.id}>
                    {divider && <div className="divider">{divider}</div>}
                    <article className="card">
                      <div className="ctop">
                        <h3>{r.name.toLowerCase()}</h3>
                        <div className="dots">
                          {Array.from({ length: n }).map((_, d) => (<span key={d} className={"dot" + (d < r.score ? " f" : "")} />))}
                        </div>
                      </div>
                      {metaTags.length > 0 && <div className="meta">{metaTags.map((t, m) => <span key={m} className="badge">{t}</span>)}</div>}
                      {r.emoji && r.emoji.length > 0 && (
                        <div className="emoji" aria-hidden="true">{r.emoji.map((e, k) => <span key={k}>{e}</span>)}</div>
                      )}
                      <ul className="ing">{r.ingredients.map((ing, j) => {
                        const a = splitAmt(ing);
                        return (
                          <li key={j}>
                            <span className="mk" />
                            <span className="tx">{a[0] && <span className="amt">{a[0]}</span>}{a[0] ? ' ' : ''}{a[1]}</span>
                          </li>
                        );
                      })}</ul>
                      <div className="cfoot">
                        <button className={"copy" + (copiedId === r.id ? " done" : "")} onClick={() => onCopy(r)}>
                          {copiedId === r.id ? 'copied ✓' : 'copy'}
                        </button>
                      </div>
                    </article>
                  </React.Fragment>
                );
              })}
              {!expanded && moreCount > 0 && <button className="more" onClick={() => setExpanded(true)}>show {moreCount} more</button>}
              {expanded && moreCount > 0 && <button className="more" onClick={() => setExpanded(false)}>show fewer</button>}
            </div>
          )
        )}
      </div>
    </div>
  );
}